using Microsoft.AspNetCore.HttpOverrides;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddScoped<IUserService, UserService>();
// Fix 3: Scoped IUserService was resolved from a singleton factory.
// .NET 9 enables ValidateScopes in development, which throws at startup.
// Use IServiceScopeFactory to resolve scoped services correctly.
builder.Services.AddSingleton<ICacheService>(sp =>
{
    using var scope = sp.GetRequiredService<IServiceScopeFactory>().CreateScope();
    return new CacheService(scope.ServiceProvider.GetRequiredService<IUserService>());
});
// Fix 1: .NET 9 HttpClientFactory defaults to SocketsHttpHandler.
// The cast to HttpClientHandler would throw InvalidCastException at runtime.
// Use ConfigurePrimaryHttpMessageHandler to set the handler type explicitly.
builder.Services.AddHttpClient("api")
    .ConfigurePrimaryHttpMessageHandler(() => new HttpClientHandler { UseCookies = false });
// Fix 2: .NET 9 redacts all HTTP header values in Trace-level logs by default.
// Allowlist specific non-sensitive headers needed for debugging.
builder.Services.ConfigureHttpClientDefaults(b =>
    b.RedactLoggedHeaders(h =>
        h != "X-Request-ID"
        && h != "X-Correlation-ID"
        && h != "Cache-Control"
        && h != "Accept"
        && h != "Content-Type"));
// Fix 4: .NET 9 ForwardedHeadersMiddleware ignores X-Forwarded-* headers
// from proxies not in KnownProxies or KnownNetworks. Configure your
// trusted proxy addresses here for the reverse proxy to work.
builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
    // TODO: Replace with your actual proxy address(es).
    options.KnownProxies.Add(System.Net.IPAddress.Loopback);
});
var app = builder.Build();
app.UseForwardedHeaders();
app.Run();

